import React, { useState, useEffect } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ onSelectUserStory, onClose, isSidebarVisible, jiraData }) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Function to fetch Jira data (optional since you're passing it as a prop)
  useEffect(() => {
    if (jiraData.length === 0) {
      setLoading(true);
      fetchJiraData();
    }
  }, [jiraData]);

  // Function to fetch Jira data if necessary
  const fetchJiraData = async () => {
    setLoading(true);
    try {
      const response = await fetch('https://localhost:7216/api/UserStoryDescription/ExportAllUserStories');
      if (!response.ok) {
        throw new Error('Failed to fetch Jira data');
      }
      setLoading(false);
    } catch (err) {
      console.error('Error fetching Jira data:', err);
      setError(`Error fetching Jira data: ${err.message}`);
      setLoading(false);
    }
  };

  return (
    <div className={`import-sidebar ${isSidebarVisible ? 'visible' : ''}`}>
      <button className="close-btn" onClick={onClose}>X</button>
      <div className="sidebar-title">Imported Jira User Stories</div>

      {loading && <div>Loading...</div>}
      {error && <div className="error">{error}</div>}

      <div className="jira-stories">
        {jiraData.length === 0 && !loading ? (
          <div>No Jira stories found.</div>
        ) : (
          jiraData.map((story) => (
            <div
              key={story.key}
              className="jira-story-box"
              onClick={() => onSelectUserStory(story)}
            >
              {story.summary}
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default ImportDataSidebar;
